for tool_id, fields in data.items():
    # Find the tool block inside TOOLS array
    pattern = r'({\s*id:\s*"' + tool_id + r'".*?)(faqItems:\s*\[)'
    
    def replacer(match):
        prefix = match.group(1)
        suffix = match.group(2)
        
        # Build the new fields string
        new_fields = f'    expertReviewer: "{fields["expertReviewer"]}",\n'
        new_fields += f'    updatedAt: "{fields["updatedAt"]}",\n'
        
        citations_str = '", "'.join(fields["legalCitations"])
        new_fields += f'    legalCitations: [\n      "{citations_str}"\n    ],\n'
        
        new_fields += f'    extendedGuide: `{fields["extendedGuide"]}`,\n'
        
        return prefix + new_fields + "    " + suffix
        
    content = re.sub(pattern, replacer, content, flags=re.DOTALL)

with open(filepath, 'w', encoding='utf-8') as f:
    f.write(content)

print(f"Updated {len(data)} tools.")
